VAR_OUTPUT
    BatchCount : INT;
    BatchComplete : BOOL;
    TotalCount : INT;
END_VAR
VAR
    SensorEdge : R_TRIG;
    Counter : CTU;
END_VAR

(* Rising edge detection for ProductSensor *)
SensorEdge(CLK := ProductSensor);

(* Count Up counter for batch tracking *)
Counter(CU := SensorEdge.Q, R := ResetBatch, PV := BatchTarget);

(* Assign counter outputs *)
BatchCount := Counter.CV;
BatchComplete := Counter.Q;

(* Increment total count on every rising edge *)
IF SensorEdge.Q THEN
    TotalCount := TotalCount + 1;
END_IF;
END_PROGRAM

FUNCTION_BLOCK MovingAverageFilter
VAR_INPUT
    Enable : BOOL;
    RawInput : REAL;
    WindowSize : INT;
END_VAR
VAR_OUTPUT
    Filtered : REAL;
END_VAR
VAR
    Buffer : ARRAY[0..9] OF REAL;
    Head : INT;
    Count : INT;
    Sum : REAL;
    EffectiveSize : INT;
    OldValue : REAL;
END_VAR
IF NOT Enable THEN
    Head := 0;
    Count := 0;
    Sum := 0.0;
    Filtered := 0.0;
ELSE
    IF WindowSize < 1 THEN
        EffectiveSize := 1;
    ELSIF WindowSize > 10 THEN
        EffectiveSize := 10;
    ELSE
        EffectiveSize := WindowSize;
    END_IF;

    IF Count < EffectiveSize THEN
        Buffer[Head] := RawInput;
        Sum := Sum + RawInput;
        Count := Count + 1;
        Head := (Head + 1) MOD 10;
    ELSE
        OldValue := Buffer[Head];
        Buffer[Head] := RawInput;
        Sum := Sum - OldValue + RawInput;
        Head := (Head + 1) MOD 10;
    END_IF;

    Filtered := Sum / INT_TO_REAL(Count);
END_IF;
END_FUNCTION_BLOCK
